#include <iostream>
#include <string>
#include <vector>

using namespace std;

const int N = 1e5 + 10;

vector<int> add(vector<int> &a, vector<int> &b) //这里加上引用，也能防止拷贝数据节省内存
{
    vector<int> c;
    int t = 0; //所有的位处理，都用t完成

    //这里很妙，不用考虑数组越界的问题
    //就是不管三七二十一继续循环，在代码块里判断有没有越界就是了
    for (int i = 0; i < a.size() || i < b.size(); i++)
    {
        if (i < a.size()) t += a[i];
        if (i < b.size()) t += b[i];

        c.push_back(t % 10);
        t = t / 10;
    }

    if (t) c.push_back(t);
    return c;
}

int main(void)
{
