## luogu P1314
二分 + 前缀和 + 数学
普及+
#### 题目描述
质检员检查矿石那道题

#### 题解
我自己做出来了！！
```
#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

using namespace std;

const int N = 200010;
const int W = 1e6 + 10; // 二分，如果不知道具体范围，就选一个合适的大整数来初始化
int n, m;
long long s, res = 1e13; // 同时结果的初始化也是
int w;
// 对于mines，第一个为重量，第二个为价值
vector<pair<int, int>> mines, queries; // 注意：矿石从1开始编号

int a[N];
int s1[N], s2[N]; // 第一个为布尔值的和，第二个为价值与布尔值的和

long long check(int w)
{
    long long res = 0;

    for (int i = 0; i < n; i++) // 构建布尔值原列表，从1开始
        a[i + 1] = (mines[i].first >= w);

    for (int i = 1; i <= n; i++) // 构建前缀和列表
    {
        s1[i] = s1[i - 1] + a[i];
        s2[i] = s2[i - 1] + a[i] * mines[i - 1].second;
    }

    for (auto item : queries) // 变量询问
        res += (s1[item.second] - s1[item.first - 1]) * (s2[item.second] - s2[item.first - 1]); // 计算检验值的和
    return res;
}

int main(void)
{
    scanf("%d %d %lld", &n, &m, &s);

    for (int i = 0; i < n; i++)
    {
        int w, v;
        scanf("%d %d", &w, &v);
        mines.push_back({w, v});
    }

    for (int i = 0; i < m; i++)
    {
        int l, r;
        scanf("%d %d", &l, &r);
        queries.push_back({l, r});
    }

    int mid, l = 0, r = W;
    long long y; // w越大，y越小
    while (l < r)
    {
        mid = l + r >> 1;
        y = check(mid);
        res = min(res, abs(y - s));

        if (s >= y) r = mid; // 标准值小了，说明要把
        else l = mid + 1;
    }

    cout << res;
}

/**
 * 二分查找的题实际上都可以用二分答案做，二分答案能保证有结果
 * 只不过最后需要手动判断一下，结果是否符合条件
 * 
 * 很不错，挑战了一个高于自己水平的题，竟然还有思路
 * 但最终败在不同类型的值的区分上
 * y我最先给的int，所以爆了，于是我一直纠结是不是我二分逻辑的问题
 * 下次注意检查的时候先检查类型是否匹配，因为这个比算法逻辑好检查一些
 *
 * 同时我也学会了题目给的数据圈定范围的能力
 * 而且理解了无限大和无限小在初始化值时候的好处
*/
```

